parameters.inputSchema:
{
  "title": "Pricing Output Schema v2",
  "type": "object",
  "additionalProperties": false,
  "required": ["generatedDate", "sections", "totalCost"],
  "properties": {
    "generatedDate": {
      "type": "string",
      "description": "报价生成日期（YYYY-MM-DD）"
    },
    "notes": {
      "type": "array",
      "description": "全局备注（如：客户提供材料、待确认假设、外包询价项说明）",
      "items": { "type": "string" }
    },
    "sections": {
      "type": "array",
      "description": "按拆解章节输出的报价结果",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": ["sectionHeader", "items", "sectionTotal"],
        "properties": {
          "sectionHeader": {
            "type": "string",
            "description": "必须与输入 sectionHeaders 中的某一项匹配（通常保持完全一致）"
          },
          "sectionTotal": {
            "type": "number",
            "description": "本章节 items subtotal 求和"
          },
          "items": {
            "type": "array",
            "description": "本章节收费条目",
            "items": {
              "type": "object",
              "additionalProperties": false,
              "required": ["name", "unitPrice", "quantityFactors", "subtotal", "isOutsourced"],
              "properties": {
                "name": {
                  "type": "string",
                  "description": "收费服务/项目名称（尽量与价格表标准名一致；可加别名括号）"
                },
                "unitPrice": {
                  "type": "number",
                  "description": "单价（元）"
                },
                "quantityFactors": {
                  "type": "object",
                  "description": "数量因子（多维）。必须至少包含 1 个键；subtotal = unitPrice × 所有数量因子乘积。键名必须使用规范中文单位键。",
                  "minProperties": 1,
                  "additionalProperties": false,
                  "properties": {
                    "只": { "type": "number", "minimum": 0, "description": "动物只数/按只计费的样本数" },
                    "天": { "type": "number", "minimum": 0, "description": "天数" },
                    "次": { "type": "number", "minimum": 0, "description": "次数/频次/批次" },
                    "笼": { "type": "number", "minimum": 0, "description": "笼数" },
                    "板": { "type": "number", "minimum": 0, "description": "板数（如ELISA等）" },
                    "张": { "type": "number", "minimum": 0, "description": "切片/图片/扫描等按张计" },
                    "部位": { "type": "number", "minimum": 0, "description": "部位数（单侧/双侧/器官部位等）" },
                    "抗体": { "type": "number", "minimum": 0, "description": "抗体数（IHC/IF等按抗体计）" },
                    "指标": { "type": "number", "minimum": 0, "description": "指标/通道/标记数（如多指标分析）" },
                    "个": { "type": "number", "minimum": 0, "description": "按“个”计的数量（如常规内脏取材或无其他适配单位）" }
                  },
                  "anyOf": [
                    { "required": ["只"] },
                    { "required": ["天"] },
                    { "required": ["次"] },
                    { "required": ["笼"] },
                    { "required": ["板"] },
                    { "required": ["张"] },
                    { "required": ["部位"] },
                    { "required": ["抗体"] },
                    { "required": ["指标"] },
                    { "required": ["个"] }]
                  }
                },
                "subtotal": {
                  "type": "number",
                  "description": "小计（元）"
                },
                "isOutsourced": {
                  "type": "boolean",
                  "description": "是否外包/价格表缺失需人工询价"
                }
              }
            }
          }
        }
      }
    },
    "totalCost": {
      "type": "number",
      "description": "总价（sections.sectionTotal 求和）"
    }
}

{
  "title": "Plan Dissector Output v2",
  "type": "object",
  "additionalProperties": false,
  "required": ["sections"],
  "properties": {
    "sections": {
      "type": "array",
      "minItems": 1,
      "description": "Ordered list of dissected sections. Order must follow the experiment document. Enforce sum(sections.content) approx. == experimentDoc",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": ["header", "content"],
        "properties": {
          "header": {
            "type": "string",
            "minLength": 1,
            "description": "Section title."
          },
          "content": {
            "type": "string",
            "minLength": 1,
            "description": "Section body text. Includes table-to-text conversion and preserves key numbers, timepoints, frequencies, and 'need confirmation' statements."
          }
        }
      }
    }
  }
}
